from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager
from flask_restful import Resource, Api
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

app = Flask(__name__)
api = Api(app)

# Set up database connection
engine = create_engine('sqlite:///users.db')
Session = sessionmaker(bind=engine)
session = Session()

# Define user model
class User(object):
    def __init__(self, id, email, username, role, account_status, subscription_tier):
        self.id = id
        self.email = email
        self.username = username
        self.role = role
        self.account_status = account_status
        self.subscription_tier = subscription_tier

# Define user resource
class UserResource(Resource):
    @jwt_required
    def put(self, user_id):
        # Get current user from JWT token
        current_user = get_jwt_identity()

        # Check if current user is an administrator
        if not current_user['is_admin']:
            return jsonify({'message': 'You do not have the necessary permissions to update this user.'}), 403

        # Get user from database
        user = session.query(User).get(user_id)

        # Check if user exists
        if not user:
            return jsonify({'message': 'User does not exist.'}), 404

        # Update user details
        user.email = request.json.get('email', user.email)
        user.username = request.json.get('username', user.username)
        user.role = request.json.get('role', user.role)
        user.account_status = request.json.get('account_status', user.account_status)
        user.subscription_tier = request.json.get('subscription_tier', user.subscription_tier)

        # Commit changes to database
        session.commit()

        return jsonify({'message': 'User updated successfully.'}), 200

# Register user resource with API
api.add_resource(UserResource, '/api/users/<user_id>')